import { useEffect, useState } from "react";
import axiosInstance from "../axiosConfig";

const Tasks = () => {
  const [plans, setPlans] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [selectedPlan, setSelectedPlan] = useState("");

  // 🔹 Fetch all plans
  const fetchPlans = async () => {
    try {
      const res = await axiosInstance.get("/api/plans");
      setPlans(res.data);
    } catch (error) {
      console.error(error);
      alert("Failed to load plans");
    }
  };

  // 🔹 Fetch user subscriptions
  const fetchSubscriptions = async () => {
    try {
      const res = await axiosInstance.get("/api/subscriptions");
      setSubscriptions(res.data);
    } catch (error) {
      console.error(error);
      alert("Failed to load subscriptions");
    }
  };

  // 🔹 Subscribe to a plan
  const handleSubscribe = async () => {
    if (!selectedPlan) {
      return alert("Please select a plan");
    }

    try {
      await axiosInstance.post("/api/subscriptions", {
        plan: selectedPlan,
      });

      alert("Subscription successful");
      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Subscription failed");
    }
  };

  // 🔹 Cancel subscription
  const handleDelete = async (id) => {
    try {
      await axiosInstance.delete(`/api/subscriptions/${id}`);
      fetchSubscriptions();
    } catch (error) {
      console.error(error);
      alert("Failed to cancel subscription");
    }
  };

  useEffect(() => {
    fetchPlans();
    fetchSubscriptions();
  }, []);

  return (
    <div className="max-w-2xl mx-auto mt-10">
      <h1 className="text-2xl font-bold text-center mb-6">
        Subscription Management
      </h1>

      {/* Plan selection */}
      <div className="mb-6">
        <select
          value={selectedPlan}
          onChange={(e) => setSelectedPlan(e.target.value)}
          className="w-full p-2 border rounded mb-2"
        >
          <option value="">Select a Plan</option>
          {plans.map((plan) => (
            <option key={plan._id} value={plan._id}>
              {plan.name} - ${plan.price}
            </option>
          ))}
        </select>

        <button
          onClick={handleSubscribe}
          className="w-full bg-green-600 text-white p-2 rounded"
        >
          Subscribe
        </button>
      </div>

      {/* Subscription list */}
      <div>
        <h2 className="text-xl font-semibold mb-2">
          My Subscriptions
        </h2>

        {subscriptions.length === 0 && (
          <p>No subscriptions yet</p>
        )}

        {subscriptions.map((sub) => (
          <div
            key={sub._id}
            className="border p-4 mb-3 rounded shadow"
          >
            <p>
              <strong>Plan:</strong> {sub.plan?.name}
            </p>
            <p>
              <strong>Status:</strong> {sub.status}
            </p>

            <button
              onClick={() => handleDelete(sub._id)}
              className="bg-red-500 text-white px-3 py-1 mt-2 rounded"
            >
              Cancel
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Tasks;
